import feapder
from feapder import Item

class ZhihuHotItem(Item):
    __tablename__ = "zhihu_hot"
    __unique_key__ = ["title"]

class ZhihuHotSpider(feapder.AirSpider):
    def start_requests(self):
        yield feapder.Request(
            "https://www.zhihu.com/hot",
            headers={"User-Agent": "Mozilla/5.0"},
        )

    def parse(self, request, response):
        # XPath/正则按实际页面结构调整；考试可写自然语言描述提取规则
        cards = response.xpath('//section')
        for card in cards:
            title = card.xpath('.//h2//text()').extract_first(default='').strip()
            heat = ''.join(card.xpath('.//*[contains(text(), "热")]/text()').extract())
            if title:
                item = ZhihuHotItem()
                item["title"] = title
                item["heat"] = heat
                item.db_save()

if __name__ == "__main__":
    ZhihuHotSpider().start()
